function getSlots(salon,staffId,svcId,ds){const d=new Date(ds+"T00:00:00"),dk=DAYS[d.getDay()],hrs=salon.hours[dk];if(!hrs||hrs==="Closed"||salon.holidays?.includes(ds))return[];if((salon.staffHolidays||[]).some(h=>h.staffId===staffId&&h.dates?.includes(ds)))return[];const svc=salon.services.find(s=>s.id===svcId);if(!svc)return[];const[os,cs]=hrs.split("-"),o=pt(os),c=pt(cs),om=o.h*60+o.m,cm=c.h*60+c.m,slots=[];for(let t=om;t+svc.duration<=cm;t+=15){if(!salon.bookings?.some(b=>b.staffId===staffId&&b.date===ds&&!(t>=b.startMin+b.duration||t+svc.duration<=b.startMin)))slots.push(t)}return slots}
