  const cats=useMemo(()=>{const c={};salon.services.forEach(s=>{(c[s.category]=c[s.category]||[]).push(s)});return c},[salon]);
  const dates=useMemo(()=>Array.from({length:21},(_,i)=>{const d=new Date(today);d.setDate(d.getDate()+i);return d}),[]);
  const slots=useMemo(()=>!selDate||!selStaff||!selSvc?[]:getSlots(salon,selStaff.id,selSvc.id,fd(selDate)),[salon,selStaff,selSvc,selDate]);
  const myBk=useMemo(()=>loggedIn?(salon.bookings||[]).filter(b=>(authEmail&&b.clientEmail===authEmail)||(cPhone&&b.clientPhone===cPhone)).sort((x,y)=>x.date<y.date?-1:x.date>y.date?1:x.startMin-y.startMin):[]  ,[salon.bookings,authEmail,cPhone,loggedIn]);
  const myUp=myBk.filter(b=>b.date>=todayS);
  const book=async()=>{const bk={id:uid(),serviceId:selSvc.id,staffId:selStaff.id,date:fd(selDate),startMin:selTime,duration:selSvc.duration,clientName:cName,clientPhone:cPhone,clientEmail:authEmail?.toLowerCase()||"",createdAt:new Date().toISOString()};const u={...salon,bookings:[...(salon.bookings||[]),bk]};const em=authEmail?.toLowerCase();if(em&&!u.clients?.find(c=>c.email===em))u.clients=[...(u.clients||[]),{id:uid(),name:cName,phone:cPhone,email:em,visits:1,lastVisit:fd(today),noShows:0}];await S.set("salon:"+salon.id,u);setSalon(u);setStep("done")};
  const cancelBk=async id=>{await S.set("salon:"+salon.id,{...salon,bookings:salon.bookings.filter(b=>b.id!==id)});setSalon({...salon,bookings:salon.bookings.filter(b=>b.id!==id)});setCancelId(null)};
  const signOut=async()=>{setCName("");setCPhone("");setLoggedIn(false);setAuthEmail("");await S.del("cs:"+salon.id)};
  const doLogin=async()=>{setAuthErr("");if(!authEmail||!authPw)return setAuthErr("Enter email and password.");const ac=await S.get("ac:"+salon.id+":"+authEmail.toLowerCase());if(!ac)return setAuthErr("No account found.");if(ac.password!==authPw)return setAuthErr("Wrong password.");setCName(ac.name);setCPhone(ac.phone||"");setLoggedIn(true);await S.set("cs:"+salon.id,{loggedIn:true,name:ac.name,phone:ac.phone||"",email:ac.email});setStep("home")};
  const doReg=async()=>{setAuthErr("");if(!authName||!authEmail||!authPw)return setAuthErr("Fill all fields.");if(authPw.length<6)return setAuthErr("Password min 6 chars.");const ex=await S.get("ac:"+salon.id+":"+authEmail.toLowerCase());if(ex)return setAuthErr("Account exists.");await S.set("ac:"+salon.id+":"+authEmail.toLowerCase(),{name:authName,email:authEmail.toLowerCase(),phone:cPhone,password:authPw});setCName(authName);setLoggedIn(true);await S.set("cs:"+salon.id,{loggedIn:true,name:authName,phone:cPhone,email:authEmail.toLowerCase()});setStep("home")};
